import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String homepage;
    Bugs bugs;
    Repository repository;
    String license;
    Author author;
    bool sideEffects;
    String type;
    Exports exports;
    String main;
    String types;
    List<String> files;
    Scripts scripts;
    DevDependencies devDependencies;
    String packageManager;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.homepage,
        required this.bugs,
        required this.repository,
        required this.license,
        required this.author,
        required this.sideEffects,
        required this.type,
        required this.exports,
        required this.main,
        required this.types,
        required this.files,
        required this.scripts,
        required this.devDependencies,
        required this.packageManager,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        homepage: json["homepage"],
        bugs: Bugs.fromJson(json["bugs"]),
        repository: Repository.fromJson(json["repository"]),
        license: json["license"],
        author: Author.fromJson(json["author"]),
        sideEffects: json["sideEffects"],
        type: json["type"],
        exports: Exports.fromJson(json["exports"]),
        main: json["main"],
        types: json["types"],
        files: List<String>.from(json["files"].map((x) => x)),
        scripts: Scripts.fromJson(json["scripts"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        packageManager: json["packageManager"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "homepage": homepage,
        "bugs": bugs.toJson(),
        "repository": repository.toJson(),
        "license": license,
        "author": author.toJson(),
        "sideEffects": sideEffects,
        "type": type,
        "exports": exports.toJson(),
        "main": main,
        "types": types,
        "files": List<dynamic>.from(files.map((x) => x)),
        "scripts": scripts.toJson(),
        "devDependencies": devDependencies.toJson(),
        "packageManager": packageManager,
    };
}

class Author {
    String name;
    String email;

    Author({
        required this.name,
        required this.email,
    });

    factory Author.fromJson(Map<String, dynamic> json) => Author(
        name: json["name"],
        email: json["email"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "email": email,
    };
}

class Bugs {
    String url;

    Bugs({
        required this.url,
    });

    factory Bugs.fromJson(Map<String, dynamic> json) => Bugs(
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "url": url,
    };
}

